    64	/// Transforms an iterator of [`TableChangesScanMetadata`] into an iterator of
    65	/// [`CdfScanFile`] by visiting the engine data.
    66	pub(crate) fn scan_metadata_to_scan_file(
    67	    scan_metadata: impl Iterator<Item = DeltaResult<TableChangesScanMetadata>>,
    68	) -> impl Iterator<Item = DeltaResult<CdfScanFile>> {
