    79	/// Request that the kernel call a callback on each valid file that needs to be read for the
    80	/// scan.
    81	///
    82	/// The arguments to the callback are:
    83	/// * `context`: an `&mut context` argument. this can be anything that engine needs to pass through
    84	///   to each call
    85	/// * `CdfScanFile`: a [`CdfScanFile`] struct that holds all the metadata required to perform Change
    86	///   Data Feed
    87	///
    88	/// ## Context
    89	/// A note on the `context`. This can be any value the engine wants. This function takes ownership
    90	/// of the passed arg, but then returns it, so the engine can repeatedly call `visit_cdf_scan_files`
    91	/// with the same context.
    92	///
    93	/// ## Example
    94	/// ```ignore
    95	/// let mut context = [my context];
    96	/// for res in scan_metadata { // scan metadata table_changes_scan.scan_metadata()
    97	///     let (data, vector, remove_dv) = res?;
    98	///     context = delta_kernel::table_changes::scan_file::visit_cdf_scan_files(
    99	///        data.as_ref(),
   100	///        selection_vector,
   101	///        context,
   102	///        my_callback,
   103	///     )?;
   104	/// }
   105	/// ```
   106	pub(crate) fn visit_cdf_scan_files<T>(
   107	    scan_metadata: &TableChangesScanMetadata,
   108	    context: T,
   109	    callback: CdfScanCallback<T>,
   110	) -> DeltaResult<T> {
   111	    let mut visitor = CdfScanFileVisitor {
   112	        callback,
   113	        context,
   114	        selection_vector: &scan_metadata.selection_vector,
   115	        remove_dvs: scan_metadata.remove_dvs.as_ref(),
   116	    };
   117	
   118	    visitor.visit_rows_of(scan_metadata.scan_metadata.as_ref())?;
   119	    Ok(visitor.context)
   120	}
